    "\1\1\1\11\3\1\1\11\2\1\1\11\2\1\3\11"+
    "\1\1\1\11\4\1\1\11\1\1\2\11\1\1\3\11"+
    "\2\1\3\11\1\1\2\11\1\1\1\11\4\1\2\11"+
    "\2\1\2\11\1\1\1\11\1\1\1\11\1\1\1\11"+
    "\3\1\2\11\1\1\4\11\11\1\7\0\2\1\1\11"+
    "\6\0\2\1\2\11\1\0\2\1\1\11\1\1\2\0"+
    "\1\11\10\1\3\0\1\11\7\0\1\1\3\0\1\11"+
    "\1\0\1\11\2\1\1\0\7\1\1\0\1\11\2\0"+
    "\1\11\1\0\1\11\1\0\1\11\3\1\1\11\6\1"+
    "\4\0\5\1\3\0\1\11\1\1\3\0\1\1\1\0"+
    "\1\11\1\0\1\11";

  private static int [] zzUnpackAttribute() {
    int [] result = new int[204];
    int offset = 0;
    offset = zzUnpackAttribute(ZZ_ATTRIBUTE_PACKED_0, offset, result);
    return result;
  }

  private static int zzUnpackAttribute(String packed, int offset, int [] result) {
    int i = 0;       /* index in packed string  */
    int j = offset;  /* index in unpacked array */
    int l = packed.length();
    while (i < l) {
      int count = packed.charAt(i++);
      int value = packed.charAt(i++);
      do result[j++] = value; while (--count > 0);
    }
    return j;
  }

  /** the input device */
  private java.io.Reader zzReader;

